import{_ as i,r,o,c as s,b as e,d as a,e as c,f as l}from"./app-55c326ac.js";const d={},t=l(`<ul><li><a href="#72-%E6%A8%A1%E6%9D%BF%E8%AF%AD%E8%A8%80">7.2 模板语言</a><ul><li><a href="#721-%E5%9F%BA%E6%9C%AC%E8%AF%AD%E6%B3%95---">7.2.1 基本语法 <code>{{}} {% %}</code></a><ul><li><a href="#%E6%96%B9%E6%B3%95%E8%B0%83%E7%94%A8">方法调用</a></li><li><a href="#for%E5%BE%AA%E7%8E%AF">for循环</a></li><li><a href="#%E8%8E%B7%E5%8F%96%E8%A7%86%E5%9B%BE%E8%AE%BF%E9%97%AE%E5%9C%B0%E5%9D%80%E7%9A%84url%E6%A0%87%E7%AD%BE">获取视图访问地址的url标签</a></li><li><a href="#%E5%A4%9A%E8%A1%8C%E6%B3%A8%E9%87%8A%E7%9A%84comment%E6%A0%87%E7%AD%BE">多行注释的comment标签</a></li><li><a href="#%E5%88%A4%E6%96%AD%E5%8F%98%E9%87%8F%E7%9B%B8%E7%AD%89%E6%88%96%E4%B8%8D%E7%9B%B8%E7%AD%89%E7%9A%84%E6%A0%87%E7%AD%BE">判断变量相等或不相等的标签</a></li></ul></li><li><a href="#722-%E8%BF%87%E6%BB%A4%E5%99%A8">7.2.2 过滤器（|）</a></li><li><a href="#723-%E6%A8%A1%E6%9D%BF%E7%BB%A7%E6%89%BFblock">7.2.3 模板继承（block）</a></li></ul></li></ul><h1 id="_7-2-模板语言" tabindex="-1"><a class="header-anchor" href="#_7-2-模板语言" aria-hidden="true">#</a> 7.2 模板语言</h1><h2 id="_7-2-1-基本语法" tabindex="-1"><a class="header-anchor" href="#_7-2-1-基本语法" aria-hidden="true">#</a> 7.2.1 基本语法 <code>{{}} {% %}</code></h2><h3 id="方法调用" tabindex="-1"><a class="header-anchor" href="#方法调用" aria-hidden="true">#</a> 方法调用</h3><p>不想索引调用需要设置<code>alters_data=True</code></p><ul><li>例子</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">class</span> <span class="token class-name">A</span><span class="token punctuation">:</span>
    <span class="token keyword">def</span> <span class="token function">z</span><span class="token punctuation">(</span>self<span class="token punctuation">)</span><span class="token punctuation">:</span>
        <span class="token keyword">return</span> <span class="token string">&#39;Django&#39;</span>
    z<span class="token punctuation">.</span>alters_data <span class="token operator">=</span> <span class="token boolean">True</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="for循环" tabindex="-1"><a class="header-anchor" href="#for循环" aria-hidden="true">#</a> for循环</h3><p>在for标签的内部，可以通过访问forloop变量的属性获取迭代过程中的一些信息<br> forloop.counter从1开始计数。除此之外，forloop还包含如下一些属性。</p><ul><li>（1）counter0：与counter一样用来计数，但是它从0开始。</li><li>（2）revcounter：用来表示当前循环中剩余元素的数量。第一次迭代时，返回的是列表中元素的总数，最后一次的返回值是1。</li><li>（3）revcounter0：与revcounter的含义相同，但是由于其索引是基于0的，因此它的值等于revcounter减去1。</li><li>（4）first：返回一个布尔值，True标识为当前迭代的是第一个元素，其他位置的元素返回False。</li><li>（5）last：也是一个布尔值，迭代最后一个元素时返回True，其他情况为False。</li><li>（6）parentloop：对于嵌套迭代的场景，用来引用父级循环的forloop变量。</li><li>需要注意，forloop只可以在for与endfor之间使用。对于first和last属性，可以通过if标签对特定的元素做特殊处理，而像counter这类属性，常常用于调试程序。</li></ul><h3 id="获取视图访问地址的url标签" tabindex="-1"><a class="header-anchor" href="#获取视图访问地址的url标签" aria-hidden="true">#</a> 获取视图访问地址的url标签</h3><ul><li>格式：<code>{% url &#39;ns:name&#39; arg1,arg2,.... %}</code></li><li>其中，ns是视图的命名空间，name是视图的名称。如果需要，还可以给定参数构造动态的url</li><li>例如：<code>{% url &#39;post:hello&#39; %}</code></li></ul><h3 id="多行注释的comment标签" tabindex="-1"><a class="header-anchor" href="#多行注释的comment标签" aria-hidden="true">#</a> 多行注释的comment标签</h3><ul><li>格式</li></ul><div class="language-html line-numbers-mode" data-ext="html"><pre class="language-html"><code>{% comment %}
{% endcomment %}
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="判断变量相等或不相等的标签" tabindex="-1"><a class="header-anchor" href="#判断变量相等或不相等的标签" aria-hidden="true">#</a> 判断变量相等或不相等的标签</h3><ul><li>提供了<code>ifequal</code>和<code>ifnotequal</code>标签，用于判断变量是否相等</li><li>v1、v2除了可以是模板变量，也可以是硬编码的字符串、整数或小数，但不可以是字典、列表等类型</li></ul><div class="language-html line-numbers-mode" data-ext="html"><pre class="language-html"><code>{% ifequal v1 v2 %}
{% else %}
{% endifqueal%}
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_7-2-2-过滤器" tabindex="-1"><a class="header-anchor" href="#_7-2-2-过滤器" aria-hidden="true">#</a> 7.2.2 过滤器（|）</h2>`,19),u={href:"https://weread.qq.com/web/reader/6e4329007193f1e66e43129k19c3222022419ca14e7eef7",target:"_blank",rel:"noopener noreferrer"},h=l('<h2 id="_7-2-3-模板继承-block" tabindex="-1"><a class="header-anchor" href="#_7-2-3-模板继承-block" aria-hidden="true">#</a> 7.2.3 模板继承（block）</h2><ul><li><p>模板继承使用起来非常简单，只需要定义好被继承的父模板，其中包含通用元素和可以被子模板覆盖的block部分即可</p></li><li><p>（1）block标签成对出现，需要<code>{%endblock%}</code>标记结束。</p></li><li><p>（2）需要给block标签起个名字，子模板中具有同样名称的block块完成对父模板的替换。</p></li><li><p>（3）子模板不需要定义父模板中的所有block，未定义时，子模板将原样使用父模板中的内容。</p></li><li><p>（4）子模板需要使用<code>{%extends%}</code>标签继承父模板，且其必须是模板中的第一个标签，通常继承声明会放在文件的第一行</p></li><li><p><code>{{block.super}}</code>变量，可以获取到父模板中渲染后的结果</p></li></ul><blockquote><p>Django建议，父模板中的{%block%}标签应该越多越好，毕竟，子模板不需要完全重写所有的标签，所以，可以多定义一些通用或者默认的内容</p></blockquote>',3);function p(E,f){const n=r("ExternalLinkIcon");return o(),s("div",null,[t,e("p",null,[a("过滤器用于在显示变量之前对变量的值进行调整，它们在模板中很常见，使用管道符号（|）指定；有些过滤器可以接受参数，如果参数中带有空格，则需要用引号括起来 参考:"),e("a",u,[a("https://weread.qq.com/web/reader/6e4329007193f1e66e43129k19c3222022419ca14e7eef7"),c(n)])]),h])}const b=i(d,[["render",p],["__file","02：模板语言.html.vue"]]);export{b as default};
